#!/usr/bin/env python3
"""Update TUTORIAL_SECTIONS for v2.14.2 — reflect current manual-hardcore game."""
from pathlib import Path

path = Path(__file__).resolve().parents[1] / "index.html"
s = path.read_text()

start = s.find("const TUTORIAL_SECTIONS=[")
end = s.find("];const DUNGEON_GUIDE_SECTIONS=[", start)
if start < 0 or end < 0:
    raise SystemExit("TUTORIAL_SECTIONS anchor not found")

NEW = r"""const TUTORIAL_SECTIONS=[{title:{zh:'一、歡迎來到夜之城',en:'1. Welcome to Night City'},paragraphs:{zh:['MUX text-rpg（文字地城）是一款免安裝的瀏覽器硬核文字 RPG。你將在夜之城探索地城、收集裝備、強化角色，並可與其他玩家聊天。','現版本為純手動戰鬥：所有地城皆需親自移動與作戰，沒有掛機或無人機代打。','死亡會累積記憶崩壞（削弱屬性），達 100% 永久刪角。每趟地城隨機布局、詞綴、每日詛咒與事件格，請謹慎規劃路線。'],en:['MUX text-rpg is a browser hardcore text RPG—no install required. Explore dungeons, collect gear, grow your character, and chat in Night City.','The current version is manual-only: every dungeon requires you to move and fight yourself—no idle or drone auto-clear.','Death raises Memory Decay (weakens stats); at 100% your character is permanently lost. Each run rolls layout, modifiers, daily curse, and event cells.']}},{title:{zh:'二、帳號、存檔與設定',en:'2. Account, Saves & Settings'},paragraphs:{zh:['首次進入會看到「MTO MUX TEXT ONLINE 帳號」視窗，可「登入」或「註冊」雲端帳號。雲端存檔端到端加密，可跨裝置同步。','舊玩家可用「匯入本機舊存檔」；亦可略過帳號，以訪客身份進入（歡迎畫面按 Esc）。','狀態欄「設定」可調整介面縮放、文字大小、語言，查看帳號與雲端同步，並開啟「新手教學」與「歷史遊戲版本」。','狀態欄另有「排行榜」可查看等級排行。「登出帳號」「刪除帳號」在設定內；刪除後本地與雲端進度將清除。'],en:['On first launch you see the MTO account overlay—register or log in for encrypted cloud saves across devices.','Legacy players can import a local save, or press Esc on the welcome screen as a guest.','Settings adjusts UI scale, text size, language, account info, cloud sync, Beginner Tutorial, and version history.','The status bar Leaderboard shows level rankings. Log out and Delete account are in Settings and wipe all progress.']}},{title:{zh:'三、大廳介面導覽',en:'3. Hub UI Tour'},paragraphs:{zh:['頂部狀態欄：頭像（點擊可上傳）、玩家名、等級、金幣、超載晶片、排行榜與設定。','狀態欄下方有藍色「角色經驗」條，顯示升級進度（聊天室內會隱藏）。','快捷按鈕：「> 地城」進入冒險、「> 商店系統」購買補給。','底部分頁：日誌（戰鬥記錄）、裝備、聊天室、背包、合成、個人。桌面寬螢幕左側會固定顯示日誌欄。'],en:['Top status bar: avatar (tap to upload), name, level, gold, overload chips, Leaderboard, and Settings.','Below it is the blue XP bar (hidden while chat is open).','Quick buttons: \"> Dungeon\" and \"> Shop\".','Bottom tabs: Log, Equipment, Chat, Inventory, Craft, Profile. Desktop shows a log sidebar.']}},{title:{zh:'四、地城進入與難度',en:'4. Entering Dungeons & Difficulty'},paragraphs:{zh:['點「> 地城」打開地城列表，每段顯示 Lv.1-3、Lv.4-6 等等級範圍，可展開已通關段落。','須通關該段普通與困難頭目，才能解鎖下一段；角色等級不可高於段落上限太多（約 ±5 級）。','選定等級後進入「選擇難度」：普通（x1.0）、困難（x1.8）、地獄（x3.0，需地獄門禁卡 #）。','每趟隨機布局（開闊/密集/獵殺/分散）；普通 1 個詞綴、困難 2 個、地獄 3 個，並附加全服「今日詛咒」。','適等級普通地城約一趟升 1 級；擊敗王有額外通關經驗。進入地城後快捷按鈕隱藏，改為地圖與戰鬥介面。'],en:['Tap \"> Dungeon\" for tiers like Lv.1-3, Lv.4-6; cleared tiers can be expanded.','Clear both Normal and Hard bosses to unlock the next tier; your level must be within ~5 of the tier cap.','Pick difficulty: Normal (x1.0), Hard (x1.8), Hell (x3.0, needs Hell Ticket #).','Each run rolls a layout (Open/Dense/Hunter/Scatter); Normal 1 modifier, Hard 2, Hell 3, plus the global daily curse.','Matching Normal tier gives ~1 level per run; boss kills grant bonus clear XP. Quick buttons hide inside dungeons.']}},{title:{zh:'五、每日詛咒與地城教學',en:'5. Daily Curse & Dungeon Guide'},paragraphs:{zh:['全服每日詛咒會附加在每趟地城，強化敵人或削弱玩家，通常伴隨更高掉落或經驗。','地城列表、選擇難度與進行中地圖上方會顯示「今日詛咒」；右側黃色「!」可開啟「地城教學」。','地城教學含解鎖規則、難度說明、布局/詞綴/詛咒列表與實戰攻略，建議入場前先看。','帶今日詛咒通關可額外降低記憶崩壞 2%。週末部分詛咒活動可能有加成（以版本公告為準）。'],en:['A global daily curse is added to every run—buffing enemies or weakening you, often with better drops or XP.','Today\'s curse appears in the dungeon list, difficulty picker, and above the in-run map; tap the yellow \"!\" for the Dungeon Guide.','The guide covers unlock rules, difficulties, layouts, modifiers, curses, and combat tips—read it before entry.','Clearing with the daily curse grants an extra -2% Memory Decay. Weekend curse events may apply per patch notes.']}},{title:{zh:'六、地圖移動與戰鬥',en:'6. Map Movement & Combat'},paragraphs:{zh:['地城為 7×7 格子地圖。點擊與角色相鄰的格子可移動；遇到怪物、精英或頭目格會進入戰鬥。','戰鬥中按「[主手攻擊]」「[副手攻擊]」輪流出手，注意攻擊冷卻；畫面顯示生命、護盾、攻擊、速度、暴率、閃避等。','擊敗敵人獲得金幣與經驗；升級回滿生命並獲得天賦點。可按「[逃脫]」嘗試離開單場戰鬥。','速度影響出手頻率；敵人閃避隨樓層成長，後期需暴擊與全傷害詞綴。擊敗頭目後可離開或繼續清圖。'],en:['Dungeons use a 7×7 grid. Tap adjacent cells to move; monsters, elites, and bosses start combat.','Use [Main-hand Attack] and [Off-hand Attack]; mind attack cooldowns. Stats include HP, shield, ATK, SPD, crit, dodge.','Kills grant gold and XP; leveling refills HP and awards talent points. [Escape] tries to flee one fight.','Speed affects turn rate; enemy dodge scales with floor—crit and all-dmg matter late game. After a boss you may leave or keep fighting.']}},{title:{zh:'七、草藥與自動回復',en:'7. Herbs & Auto-heal'},paragraphs:{zh:['草藥分 +低、+中、+高 三種，在「背包」→「道具 (點擊使用)」中點擊即可使用。','戰鬥畫面可開啟「自動草藥」：勾選後設定「低於」15%/30%/50% 生命時，自動使用指定草藥。','進入地城前若已啟用自動草藥，系統會在必要時提示或自動消耗。','合理配置草藥是長期地城生存的關鍵，請在商店或掉落中保持庫存。'],en:['Herbs come in low/mid/high tiers—use them from Inventory → Items (tap to use).','In combat, enable Auto Herb: pick a threshold (15/30/50%) and which herb to use.','Auto herb may trigger before or during dungeon runs when enabled.','Stock herbs from drops and shops for longer dungeon runs.']}},{title:{zh:'八、裝備與背包',en:'8. Equipment & Inventory'},paragraphs:{zh:['「裝備」分頁上方為六格已裝備欄：主手、副手、護甲、護臂、腿甲、鞋子。','下方為裝備背包（基礎 60 格，可用背包石擴充）。長按裝備可查看詳情，點擊可裝備、卸下、回收、升級或鎖定。','裝備有普通、稀有、史詩、傳說、隱藏等稀有度，詞綴會影響攻擊、防禦、暴率、閃避、金幣加成等。','可使用一鍵裝備、一鍵卸下、一鍵回收與「裝備篩選」快速整理；鎖定裝備不會被回收。','「背包」分頁存放道具、材料與天賦點；裝備與道具分開管理。'],en:['Equipment tab: six worn slots plus a bag (60 base slots, expandable with bag stones).','Long-press gear for details; tap to equip, unequip, recycle, upgrade, or lock.','Rarities from common to hidden; affixes affect ATK, DEF, crit, dodge, gold bonus, etc.','Use equip-all, unequip-all, recycle-all, and filters; locked items are safe from recycle.','Inventory tab holds consumables, materials, and talent points separately from gear.']}},{title:{zh:'九、合成台與材料',en:'9. Craft Station & Materials'},paragraphs:{zh:['「合成」分頁可使用合成台將低級草藥合成中級、高級草藥，或用裝備碎片 $ 隨機合成裝備。','合成台等級會跟隨玩家等級上限；等級越高，可合成物品價值越高。','裝備碎片來自「裝備回收」；升級石 * 等素材可在地城或商店取得。','合成需手動操作並消耗材料，沒有離線掛機合成。'],en:['Craft tab: combine herbs tier-up, or spend equip fragments $ for random gear.','Craft station level caps at your player level; higher level unlocks better recipes.','Fragments come from recycling gear; upgrade stones and more drop in dungeons or shops.','Crafting is manual and costs materials—there is no offline craft idle.']}},{title:{zh:'十、商店與超載晶片',en:'10. Shop & Overload Chips'},paragraphs:{zh:['「> 商店系統」主選單：系統裝備補給商店（定時刷新裝備）、荒坂貨幣補給站（充值晶片）、超載晶片商店（特殊道具）。','金幣可在裝備商店購買補給；超載晶片為付費貨幣，可購買改名卡、武器箱破解器等。','狀態欄「超載晶片:」與「金幣:」分開顯示，請注意各自用途。'],en:['\"> Shop\" menu: rotating equip supply, Arasaka recharge (chips), and chip item shop.','Gold buys gear refreshes; overload chips (paid) buy rename cards, decoders, etc.','Gold and chips are separate currencies in the status bar.']}},{title:{zh:'十一、天賦、經驗與成長',en:'11. Talents, XP & Growth'},paragraphs:{zh:['每次升級獲得 1 天賦點，在「背包」點擊天賦點或開啟「天賦」視窗分配：生命、防禦、攻擊、逃脫、速度。','適等級地城一趟約升 1 級；刷低層會因等級差減少經驗。擊敗王有通關經驗加成。','同日同地城第 3 趟起進入疲勞：金幣 ×82%、經驗 ×90%。','「個人」分頁可查看戰鬥屬性、天賦、裝備摘要、記憶崩壞與統計；藍色經驗條顯示升級進度。'],en:['Each level grants 1 talent point for HP, DEF, ATK, escape, and speed.','Matching-tier runs give ~1 level per clear; farming low tiers penalizes XP. Boss kills add clear bonus XP.','3+ runs of the same dungeon per day: gold ×82%, XP ×90% (fatigue).','Profile shows combat stats, talents, gear summary, decay, and stats; the blue XP bar tracks progress.']}},{title:{zh:'十二、記憶崩壞與永久死亡',en:'12. Memory Decay & Permanent Death'},paragraphs:{zh:['「個人」面板顯示記憶崩壞值（0%～100%）。戰鬥死亡會增加崩壞（部分隱藏裝備可避免一次死亡）。','崩壞值越高屬性越弱；日誌會警告高崩壞風險。達 100% 觸發永久死亡，只能創建新角色。','通關可緩解崩壞：普通 -2%、困難 -5%、地獄 -8%；帶今日詛咒通關再 -2%。','聖壇等事件格也可能小幅影響崩壞。請在崩壞偏高時降低難度、補給充足再挑戰。'],en:['Profile shows Memory Decay 0–100%. Combat death adds decay (some hidden gear prevents one death).','Higher decay weakens stats; logs warn at high risk. At 100% you get permanent death—only a new character remains.','Clear relief: Normal -2%, Hard -5%, Hell -8%; daily curse clear adds -2%.','Shrines and events may also affect decay. Lower difficulty and heal up when decay is high.']}},{title:{zh:'十三、聊天與雲端同步',en:'13. Chat & Cloud Sync'},paragraphs:{zh:['「聊天室」分頁可進入多人聊天（需網路）。輸入訊息後按「發送」；手機版為全螢幕覆蓋層。','聊天訊息旁顯示玩家等級；長按玩家名可查看對方公開資訊。','登入雲端帳號後，設定內「雲端同步」會顯示在線／離線／已同步等狀態。','可手動「立即同步至雲端」；建議在重要進度後手動同步，並保持穩定網路。'],en:['Chat tab opens multiplayer chat (network required). Type a message and tap Send.','Messages show player level; long-press a name for their public profile.','After cloud login, Settings shows cloud sync status: online, offline, synced, etc.','Tap Sync to Cloud after major progress and keep a stable connection.']}},{title:{zh:'十四、建議新手流程',en:'14. Recommended First Steps'},paragraphs:{zh:['1. 登入或註冊雲端帳號，設定玩家名字與頭像。','2. 點「> 地城」→ 選最低等級段 →「普通」；入場前點「!」瀏覽地城教學與今日詛咒。','3. 地圖上點相鄰格移動，遇敵用主手／副手攻擊；勝利後到「裝備」分頁穿戴掉落。','4. 在背包準備草藥，戰鬥中可開啟自動草藥。','5. 擊敗頭目後離開地城，確認經驗成長；再挑戰困難難度以解鎖下一段。','6. 熟悉後嘗試合成、商店補給與困難／地獄挑戰。祝你在夜之城生存順利！'],en:['1. Register/log in, set your name and avatar.','2. Tap \"> Dungeon\" → lowest tier → Normal; tap \"!\" to read the guide and today\'s curse.','3. Move on the map, fight with main/off attacks, equip drops from the Equipment tab.','4. Stock herbs in Inventory; enable Auto Herb in combat.','5. Beat the boss, leave, check XP growth, then try Hard to unlock the next tier.','6. Later explore craft, shop supplies, and Hard/Hell challenges. Good luck in Night City!']}}"""

s = s[:start] + NEW + s[end:]

# version bump
s = s.replace("GAME_VERSION='2.14.1'", "GAME_VERSION='2.14.2'", 1)
s = s.replace(
    "GAME_VERSION_HISTORY=[{version:'2.14.0'",
    "GAME_VERSION_HISTORY=[{version:'2.14.2',date:'2026-06-08',summary:{zh:'v2.14.2 新手教學更新：貼合純手動硬核與地城教學。',en:'v2.14.2 tutorial refresh for manual hardcore and dungeon guide.'}},{version:'2.14.0'",
    1,
)

path.write_text(s)
print("v2.14.2 tutorial update OK")
